 12166→nsresult nsHttpChannel::TriggerNetwork() {
 12167→  MOZ_ASSERT(NS_IsMainThread(), "Must be called on the main thread");
 12168→
 12169→  LOG(("nsHttpChannel::TriggerNetwork [this=%p]\n", this));
 12170→
 12171→  if (mCanceled) {
 12172→    LOG(("  channel was canceled.\n"));
 12173→    return mStatus;
 12174→  }
 12175→
 12176→  // If a network request has already gone out, there is no point in
 12177→  // doing this again.
 12178→  if (mNetworkTriggered) {
 12179→    LOG(("  network already triggered. Returning.\n"));
 12180→    return NS_OK;
 12181→  }
 12182→
 12183→  mNetworkTriggered = true;
 12184→  if (mNetworkTriggerTimer) {
 12185→    mNetworkTriggerTimer->Cancel();
 12186→    mNetworkTriggerTimer = nullptr;
 12187→  }
 12188→
 12189→  // If we are waiting for a proxy request, that means we can't trigger
 12190→  // the next step just yet. We need for mConnectionInfo to be non-null
 12191→  // before we call ContinueConnect. OnProxyAvailable will trigger
 12192→  // BeginConnect, and Connect will call ContinueConnect even if it's
 12193→  // for the cache callbacks.
 12194→  if (mProxyRequest) {
 12195→    LOG(("  proxy request in progress. Delaying network trigger.\n"));
 12196→    mWaitingForProxy = true;
 12197→    return NS_OK;
 12198→  }
 12199→
 12200→  // If |mCacheOpenFunc| is assigned, we're delaying opening the entry to
 12201→  // simulate racing. Although cache entry opening hasn't started yet, we're
 12202→  // actually racing, so we must set mRaceCacheWithNetwork to true now.
 12203→  mRaceCacheWithNetwork =
 12204→      AwaitingCacheCallbacks() &&
 12205→      (mCacheOpenFunc || StaticPrefs::network_http_rcwn_enabled());
 12206→
 12207→  LOG(("  triggering network rcwn=%d\n", bool(mRaceCacheWithNetwork)));
 12208→  return ContinueConnect();
 12209→}
