 12295→       aTimeout));
 12296→  MOZ_ASSERT(NS_IsMainThread(), "Must be called on the main thread");
 12297→
 12298→  // We set the trigger delay to the specified timeout.
 12299→  mRaceCacheWithNetwork = true;
 12300→  mNetworkTriggerDelay = aTimeout;
 12301→
 12302→  // If we already have a timer, set the delay/
 12303→  if (mNetworkTriggerTimer) {
 12304→    // If the timeout is 0 and there is a timer, we can trigger
 12305→    // the network immediately.
