 12342→bool nsHttpChannel::EligibleForTailing() {
 12343→  if (!(mClassOfService.Flags() & nsIClassOfService::Tail)) {
 12344→    return false;
 12345→  }
 12346→
 12347→  if (mClassOfService.Flags() &
 12348→      (nsIClassOfService::UrgentStart | nsIClassOfService::Leader |
 12349→       nsIClassOfService::TailForbidden)) {
 12350→    return false;
 12351→  }
 12352→
 12353→  if (mClassOfService.Flags() & nsIClassOfService::Unblocked &&
 12354→      !(mClassOfService.Flags() & nsIClassOfService::TailAllowed)) {
 12355→    return false;
 12356→  }
 12357→
 12358→  if (IsNavigation()) {
 12359→    return false;
 12360→  }
 12361→
 12362→  return true;
 12363→}
