 12365→bool nsHttpChannel::WaitingForTailUnblock() {
 12366→  nsresult rv;
 12367→
 12368→  if (!gHttpHandler->IsTailBlockingEnabled()) {
 12369→    LOG(("nsHttpChannel %p tail-blocking disabled", this));
 12370→    return false;
 12371→  }
 12372→
 12373→  if (!EligibleForTailing()) {
 12374→    LOG(("nsHttpChannel %p not eligible for tail-blocking", this));
 12375→    AddAsNonTailRequest();
 12376→    return false;
 12377→  }
 12378→
 12379→  if (!EnsureRequestContext()) {
 12380→    LOG(("nsHttpChannel %p no request context", this));
 12381→    return false;
 12382→  }
 12383→
 12384→  LOG(("nsHttpChannel::WaitingForTailUnblock this=%p, rc=%p", this,
 12385→       mRequestContext.get()));
 12386→
 12387→  bool blocked;
 12388→  rv = mRequestContext->IsContextTailBlocked(this, &blocked);
 12389→  if (NS_FAILED(rv)) {
 12390→    return false;
 12391→  }
 12392→
 12393→  LOG(("  blocked=%d", blocked));
 12394→
 12395→  return blocked;
 12396→}
